import{_ as e,a as i,b as t,c as o,d as n,e as d}from"./chunks/手机端显示用户管理效果.D-1yQf5H.js";import{_ as r,o as l,c as s,a2 as p}from"./chunks/framework.DnrXFDHb.js";const j=JSON.parse('{"title":"Geolokalizacja IP i zarządzanie użytkownikami","description":"","frontmatter":{},"headers":[],"relativePath":"pl-PL/Other/ip-geolocation-and-user-management.md","filePath":"pl-PL/Other/ip-geolocation-and-user-management.md","lastUpdated":1781962217000}'),z={name:"pl-PL/Other/ip-geolocation-and-user-management.md"};function c(y,a,u,w,k,b){return l(),s("div",null,[...a[0]||(a[0]=[p('<h1 id="geolokalizacja-ip-i-zarzadzanie-uzytkownikami" tabindex="-1">Geolokalizacja IP i zarządzanie użytkownikami <a class="header-anchor" href="#geolokalizacja-ip-i-zarzadzanie-uzytkownikami" aria-label="Permalink to &quot;Geolokalizacja IP i zarządzanie użytkownikami&quot;">​</a></h1><p>Geolokalizacja IP zamienia adresy IP w rekordach uploaderów, urządzeniach logowania i podobnych logach na przybliżone lokalizacje.</p><p>Po konfiguracji panel administracyjny może czytelniej pokazywać źródła uploadów i dostępu. Zarządzanie użytkownikami pozwala też blokować lub przywracać upload dla podejrzanych adresów IP.</p><h2 id="gdzie-skonfigurowac" tabindex="-1">Gdzie skonfigurować <a class="header-anchor" href="#gdzie-skonfigurowac" aria-label="Permalink to &quot;Gdzie skonfigurować&quot;">​</a></h2><p>Otwórz:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; IP Geolocation</span></span></code></pre></div><p><img src="'+e+`" alt="Geolokalizacja IP" loading="lazy"></p><h2 id="dostepne-ustawienia" tabindex="-1">Dostępne ustawienia <a class="header-anchor" href="#dostepne-ustawienia" aria-label="Permalink to &quot;Dostępne ustawienia&quot;">​</a></h2><p>Nowszy przepływ geolokalizacji IP obsługuje wiele źródeł zamiast polegać na jednej usłudze map.</p><table tabindex="0"><thead><tr><th>Ustawienie</th><th>Cel</th></tr></thead><tbody><tr><td>Język geolokalizacji IP</td><td>Wybiera język wyświetlania, np. angielski, chiński uproszczony, japoński, francuski i inne.</td></tr><tr><td>MaxMind Account ID</td><td>Account ID MaxMind dla MaxMind GeoLite Web Service.</td></tr><tr><td>MaxMind License Key</td><td>License Key MaxMind.</td></tr><tr><td>Tencent Map Key</td><td>Klucz Tencent Location Service. Przydatny dla chińskich adresów i IP z kontynentalnych Chin.</td></tr><tr><td>ipapi Key</td><td>Klucz APILayer ipapi. Obsługuje wielojęzyczną geolokalizację IP.</td></tr></tbody></table><p>Wypełnij tylko usługi, których potrzebujesz. Nie trzeba konfigurować każdego pola.</p><p>Jeśli nie podasz żadnego klucza, ImgBed nadal spróbuje wbudowanych darmowych źródeł, ale stabilność, obsługa języków i dokładność mogą być niższe niż przy usłudze skonfigurowanej samodzielnie.</p><h2 id="zalecane-wybory" tabindex="-1">Zalecane wybory <a class="header-anchor" href="#zalecane-wybory" aria-label="Permalink to &quot;Zalecane wybory&quot;">​</a></h2><p>Jeśli potrzebujesz głównie chińskich adresów:</p><ol><li>Ustaw język geolokalizacji IP na chiński uproszczony.</li><li>Skonfiguruj Tencent Map Key.</li><li>Opcjonalnie dodaj MaxMind lub ipapi jako źródła zapasowe.</li></ol><p>Jeśli potrzebujesz głównie angielskich lub wielojęzycznych adresów:</p><ol><li>Wybierz potrzebny język.</li><li>Skonfiguruj MaxMind Account ID i License Key.</li><li>Dodaj ipapi Key, jeśli potrzebujesz lepszych wyników wielojęzycznych.</li></ol><h2 id="konfiguracja-maxmind" tabindex="-1">Konfiguracja MaxMind <a class="header-anchor" href="#konfiguracja-maxmind" aria-label="Permalink to &quot;Konfiguracja MaxMind&quot;">​</a></h2><p>MaxMind wymaga:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MaxMind Account ID</span></span>
<span class="line"><span>MaxMind License Key</span></span></code></pre></div><p>Znajdź Account ID w panelu MaxMind i wygeneruj License Key na stronie License Keys.</p><p><img src="`+i+'" alt="Konfiguracja klucza MaxMind" loading="lazy"></p><p>Po wygenerowaniu wklej Account ID i License Key do ImgBed i zapisz.</p><p>Darmowy plan MaxMind nadaje się do codziennego użycia, ale ma limity zapytań. Po przekroczeniu limitu ImgBed próbuje innych dostępnych źródeł.</p><h2 id="konfiguracja-ipapi" tabindex="-1">Konfiguracja ipapi <a class="header-anchor" href="#konfiguracja-ipapi" aria-label="Permalink to &quot;Konfiguracja ipapi&quot;">​</a></h2><p>ipapi używa API Key APILayer.</p><p>Otwórz konsolę ipapi i skopiuj widoczny tam API Key.</p><p><img src="'+t+'" alt="Konfiguracja ipapi" loading="lazy"></p><p>Wklej go w polu <code>ipapi Key</code> w ImgBed i zapisz.</p><p>ipapi obsługuje wielojęzyczną geolokalizację IP i jest przydatny, gdy chcesz pokazywać adresy w wybranym języku. Darmowy plan również ma limity. Gdy limit się skończy, ImgBed próbuje innych dostępnych źródeł.</p><h2 id="konfiguracja-tencent-map-key" tabindex="-1">Konfiguracja Tencent Map Key <a class="header-anchor" href="#konfiguracja-tencent-map-key" aria-label="Permalink to &quot;Konfiguracja Tencent Map Key&quot;">​</a></h2><p>Tencent Map Key jest przydatny dla chińskich adresów, szczególnie IP z kontynentalnych Chin.</p><p>Podczas tworzenia klucza w Tencent Location Service włącz:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WebServiceAPI</span></span></code></pre></div><p>Po utworzeniu wklej klucz do <code>Tencent Map Key</code> i zapisz.</p><p>Jeśli potrzebujesz tylko podstawowej chińskiej geolokalizacji IP, Tencent Map Key wystarczy na start.</p><h2 id="co-sprawdzic-w-zarzadzaniu-uzytkownikami" tabindex="-1">Co sprawdzić w Zarządzaniu użytkownikami <a class="header-anchor" href="#co-sprawdzic-w-zarzadzaniu-uzytkownikami" aria-label="Permalink to &quot;Co sprawdzić w Zarządzaniu użytkownikami&quot;">​</a></h2><p>Zarządzanie użytkownikami jest dostępne u góry panelu administracyjnego.</p><p><img src="'+o+'" alt="Zarządzanie użytkownikami" loading="lazy"></p><p>Pokazuje aktywność uploadu według IP:</p><table tabindex="0"><thead><tr><th>Pole</th><th>Opis</th></tr></thead><tbody><tr><td>Źródło IP</td><td>Adres IP osoby przesyłającej.</td></tr><tr><td>Adres</td><td>Przybliżona lokalizacja ustalona z IP.</td></tr><tr><td>Łączny rozmiar uploadu</td><td>Łączny rozmiar plików przesłanych z tego IP.</td></tr><tr><td>Liczba uploadów</td><td>Liczba uploadów z tego IP.</td></tr><tr><td>Upload dozwolony</td><td>Włączone oznacza upload dozwolony. Wyłączone oznacza upload zablokowany.</td></tr></tbody></table><p>Kliknij strzałkę po lewej, aby rozwinąć listę plików przesłanych z tego IP.</p><p>Lista plików pokazuje nazwę, podgląd, rozmiar, wynik moderacji, status pliku i czas uploadu. Gdy uploady wyglądają podejrzanie, najpierw rozwiń IP, przejrzyj pliki, a potem zdecyduj, czy blokować dalsze uploady.</p><p>Jeśli IP jest podejrzany, wyłącz <code>Upload allowed</code>. Przyszłe uploady z tego IP będą blokowane.</p><h2 id="wyszukiwanie-sortowanie-i-filtry-zaawansowane" tabindex="-1">Wyszukiwanie, sortowanie i filtry zaawansowane <a class="header-anchor" href="#wyszukiwanie-sortowanie-i-filtry-zaawansowane" aria-label="Permalink to &quot;Wyszukiwanie, sortowanie i filtry zaawansowane&quot;">​</a></h2><p>U góry Zarządzania użytkownikami możesz wyszukiwać po IP źródłowym lub adresie.</p><p>Sortuj po czasie, liczbie uploadów albo łącznym rozmiarze, aby znaleźć ostatnich uploaderów, częstych uploaderów albo IP o dużym użyciu.</p><p>Do głębszej analizy otwórz filtry zaawansowane.</p><p><img src="'+n+'" alt="Filtry zaawansowane" loading="lazy"></p><p>Filtry zaawansowane obsługują:</p><table tabindex="0"><thead><tr><th>Filtr</th><th>Zastosowanie</th></tr></thead><tbody><tr><td>Zakres czasu</td><td>Pokazuje IP, które przesyłały pliki w wybranym okresie.</td></tr><tr><td>Status dostępu</td><td>Filtruje według normalnego, zablokowanego i podobnych statusów.</td></tr><tr><td>Allow/block list</td><td>Filtruje według allowlist, blocklist albo braku ustawienia.</td></tr><tr><td>Typ pliku</td><td>Pokazuje IP, które przesyłały obrazy, wideo, audio, dokumenty, kod lub inne pliki.</td></tr><tr><td>Rozmiar pliku</td><td>Filtruje według zakresu rozmiaru przesłanych plików.</td></tr><tr><td>Rating wiekowy</td><td>Filtruje według braku ustawienia, General, R12+, R16+, R18 i podobnych.</td></tr><tr><td>Status pliku</td><td>Filtruje według bieżącego statusu pliku, aby badać nietypowe pliki.</td></tr></tbody></table><p>Kliknij <code>Apply Filters</code>, aby zastosować. Użyj <code>Reset</code>, aby wrócić do wszystkich danych.</p><h2 id="widok-mobilny" tabindex="-1">Widok mobilny <a class="header-anchor" href="#widok-mobilny" aria-label="Permalink to &quot;Widok mobilny&quot;">​</a></h2><p>Na telefonie Zarządzanie użytkownikami przełącza się na układ kart.</p><p><img src="'+d+`" alt="Mobilne zarządzanie użytkownikami" loading="lazy"></p><p>Każda karta pokazuje IP, adres, łączny rozmiar uploadu, liczbę uploadów i przełącznik zezwolenia na upload. Możesz zarządzać użytkownikami bez przewijania szerokiej tabeli.</p><h2 id="jesli-lokalizacja-wyglada-niepoprawnie" tabindex="-1">Jeśli lokalizacja wygląda niepoprawnie <a class="header-anchor" href="#jesli-lokalizacja-wyglada-niepoprawnie" aria-label="Permalink to &quot;Jeśli lokalizacja wygląda niepoprawnie&quot;">​</a></h2><p>Geolokalizacja IP jest przybliżona. To nie jest dokładny adres ulicy.</p><p>Jeśli użytkownik korzysta z proxy, data center, serwera chmurowego albo sieci transgranicznej, pokazywana lokalizacja może różnić się od rzeczywistej.</p><p>Używaj tej funkcji do orientacyjnego zrozumienia źródła, wykrywania nietypowych uploadów i wspierania decyzji o blokadzie. Nie traktuj jej jako precyzyjnego śledzenia.</p><h2 id="typowe-sytuacje" tabindex="-1">Typowe sytuacje <a class="header-anchor" href="#typowe-sytuacje" aria-label="Permalink to &quot;Typowe sytuacje&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Sytuacja</th><th>Znaczenie</th></tr></thead><tbody><tr><td>Adres jest pusty</td><td>IP mogło jeszcze nie zostać rozwiązane albo bieżące źródło jest chwilowo niedostępne.</td></tr><tr><td>Język adresu jest zły</td><td>Sprawdź język geolokalizacji IP i czy skonfigurowane źródło obsługuje ten język.</td></tr><tr><td>Adres pokazuje data center</td><td>Wiele proxy, serwerów chmurowych i crawlerów wygląda jak data center lub adres ISP.</td></tr><tr><td>Liczba uploadów jest wysoka</td><td>Dokładnie sprawdź ten IP i zablokuj uploady, jeśli trzeba.</td></tr><tr><td>Łączny rozmiar jest duży</td><td>Posortuj lub przefiltruj, rozwiń IP i sprawdź konkretne pliki.</td></tr><tr><td>Trzeba przywrócić po blokadzie</td><td>Włącz ponownie <code>Upload allowed</code>.</td></tr></tbody></table><h2 id="szybki-przebieg" tabindex="-1">Szybki przebieg <a class="header-anchor" href="#szybki-przebieg" aria-label="Permalink to &quot;Szybki przebieg&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Otwórz IP Geolocation w Other Settings</span></span>
<span class="line"><span>-&gt; Wybierz język geolokalizacji IP</span></span>
<span class="line"><span>-&gt; Wpisz dane MaxMind, Tencent Map lub ipapi według potrzeb</span></span>
<span class="line"><span>-&gt; Zapisz ustawienia</span></span>
<span class="line"><span>-&gt; Otwórz Zarządzanie użytkownikami</span></span>
<span class="line"><span>-&gt; Sprawdź IP, adres, łączny rozmiar i liczbę uploadów</span></span>
<span class="line"><span>-&gt; Użyj wyszukiwania, sortowania lub filtrów zaawansowanych, aby znaleźć nietypowe IP</span></span>
<span class="line"><span>-&gt; Zezwól lub zablokuj uploady według potrzeb</span></span></code></pre></div>`,64)])])}const m=r(z,[["render",c]]);export{j as __pageData,m as default};
